mapper.select:
SELECT br.id, br.user_id, u.username, u.real_name, br.book_id, b.title AS book_title, b.isbn AS book_isbn, br.borrow_date, br.due_date, br.return_date, br.status, br.remark, br.create_time, br.update_time FROM borrow_record br LEFT JOIN sys_user u ON br.user_id = u.id AND u.deleted = 0 LEFT JOIN book_info b ON br.book_id = b.id AND b.deleted = 0 WHERE br.deleted = 0
AND br.user_id = #{userId}
AND br.book_id = #{bookId}
AND br.status = #{status}
ORDER BY br.create_time DESC
